const DEFAULT_API='https://cove-api.jeff-r-winters.workers.dev';
    const state={boats:[],captains:[],bookings:[],availability:[],selectedBoatId:null,selectedCaptainId:null,media:[],calendarMonth:new Date(new Date().getFullYear(),new Date().getMonth(),1),bookingFilters:{status:'',boatId:'',captainId:'',from:'',to:'',search:''}};
    const fields=['name','slug','status','lengthFt','capacity','bedrooms','bathrooms','make','model','type','homePort','shortDescription','startingPrice','priceUnit'];
    const captainFields=['captainName','captainStatus','captainCredential','captainEmail','captainPhone','captainHomePort','captainBio'];
    const money=v=>new Intl.NumberFormat('en-US',{style:'currency',currency:'USD',maximumFractionDigits:0}).format(Number(v||0));
    const api=()=>localStorage.getItem('cove_api_base')||DEFAULT_API;
    const token=()=>localStorage.getItem('cove_admin_token')||'';
    const esc=value=>String(value??'').replace(/[&<>"']/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));
    const timeText=()=>new Date().toLocaleTimeString([], {hour:'numeric', minute:'2-digit'});
    apiBase.value=api();
    adminToken.value=token();
    function adminHeaders(extra={}){const headers={...extra};if(token())headers.Authorization=`Bearer ${token()}`;return headers;}
    function updateAuthStatus(health){authStatus.textContent=token()?`Admin token saved locally. API protected writes: ${health?.adminAuth?'enabled':'unknown'}.`:'No admin token saved.';}
    saveApiBase.onclick=()=>{localStorage.setItem('cove_api_base',apiBase.value.trim()||DEFAULT_API);localStorage.setItem('cove_admin_token',adminToken.value.trim());loadHealth();loadBoats();};
    clearAdminToken.onclick=()=>{localStorage.removeItem('cove_admin_token');adminToken.value='';updateAuthStatus();};
    function go(tab){document.querySelectorAll('.tab').forEach(t=>t.classList.toggle('active',t.id===tab));document.querySelectorAll('[data-tab]').forEach(b=>b.classList.toggle('active',b.dataset.tab===tab));if(tab==='boats')showBoatList();if(tab==='captains')renderCaptains();if(tab==='bookings')renderBookings();if(tab==='json')renderJson();}
    document.querySelectorAll('[data-tab]').forEach(b=>b.addEventListener('click',()=>go(b.dataset.tab)));
    function showBoatList(){state.selectedBoatId=null;state.media=[];boatListScreen.classList.remove('hidden');boatDetailScreen.classList.add('hidden');}
    function showBoatDetail(){boatListScreen.classList.add('hidden');boatDetailScreen.classList.remove('hidden');scrollTo({top:0,behavior:'smooth'});}
    function updateStats(){statBoats.textContent=state.boats.length;statActive.textContent=state.boats.filter(b=>b.status==='active').length;bindHalfHourTimes(bookingList);updateBookingBadges();}
    function updateBookingBadges(){const newCount=state.bookings.filter(b=>b.status==='requested').length;statNewBookings.textContent=newCount;statBookings.textContent=state.bookings.length;bookingNavCount.textContent=newCount;bookingNavCount.classList.toggle('hidden',newCount===0);mobileBookingCount.textContent=newCount?`(${newCount})`:'';}
    async function loadHealth(){try{const r=await fetch(`${api()}/api/v1/health`);const d=await r.json();statApi.textContent=d.d1?'OK':'--';updateAuthStatus(d);}catch{statApi.textContent='ERR';updateAuthStatus();}}
    async function loadBoats(){boatLoadStatus.textContent='Loading boats from Cove API...';try{const r=await fetch(`${api()}/api/v1/boats`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load boats');state.boats=d;renderBoats();}catch(e){boatLoadStatus.textContent=e.message;boatList.innerHTML='<div class="item">Could not load boats from API.</div>';}}
    function orderedBoats(){return [...state.boats].sort((a,b)=>Number(a.sortOrder||0)-Number(b.sortOrder||0)||String(a.name||'').localeCompare(String(b.name||'')));}
    function renderBoats(){const boats=orderedBoats();boatList.innerHTML=boats.map((b,i)=>`<article class="item click" draggable="true" data-id="${esc(b.id)}"><div class="item-top"><div><h3>${esc(b.name)}</h3><p>${b.lengthFt||'--'} ft | ${b.capacity||'--'} guests | ${b.startingPrice?money(b.startingPrice):'Contact for pricing'}</p></div><span class="badge ${b.status==='active'?'good':'bad'}">Open</span></div><div class="pill-row"><span class="pill">Display ${i+1}</span><span class="pill">${esc(b.status)}</span><span class="pill">${b.featured?'Featured':'Standard'}</span><span class="pill">${b.bookingEnabled?'Booking enabled':'Booking disabled'}</span><span class="pill">${(b.approvedCaptainIds||[]).length} approved captains</span></div></article>`).join('')||'<div class="item">No boats found.</div>';boatList.querySelectorAll('.item.click').forEach(i=>i.onclick=()=>selectBoat(i.dataset.id));bindBoatDrag();boatLoadStatus.textContent=`${state.boats.length} boat records loaded from D1. Drag boat cards to change public display order.`;renderBookingFilters();if(state.selectedCaptainId)renderCaptainBoatApprovals();updateStats();renderJson();}
    function bindBoatDrag(){boatList.querySelectorAll('[draggable="true"]').forEach(card=>{card.ondragstart=e=>{card.classList.add('dragging');e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain',card.dataset.id);};card.ondragend=()=>card.classList.remove('dragging');card.ondragover=e=>{e.preventDefault();e.dataTransfer.dropEffect='move';};card.ondrop=e=>{e.preventDefault();reorderBoats(e.dataTransfer.getData('text/plain'),card.dataset.id).catch(err=>alert(err.message));};});}
    async function reorderBoats(sourceId,targetId){if(!sourceId||!targetId||sourceId===targetId)return;const boats=orderedBoats();const from=boats.findIndex(b=>b.id===sourceId);const to=boats.findIndex(b=>b.id===targetId);if(from<0||to<0)return;const [moved]=boats.splice(from,1);boats.splice(to,0,moved);const boatIds=boats.map(b=>b.id);state.boats=state.boats.map(b=>({...b,sortOrder:boatIds.indexOf(b.id)}));renderBoats();boatLoadStatus.textContent='Saving public boat order...';const r=await fetch(`${api()}/api/v1/boats/order`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({boatIds})});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not save boat order');boatLoadStatus.textContent='Public boat order saved.';await loadBoats();}
    function selectBoat(id){state.selectedBoatId=id;const b=state.boats.find(x=>x.id===id);if(!b)return;showBoatDetail();detailTitle.textContent=b.name;detailSummary.textContent=b.shortDescription||'';detailStatus.textContent=b.status||'boat';detailPills.innerHTML=[`${b.lengthFt||'--'} ft`,`${b.capacity||'--'} guests`,b.startingPrice?money(b.startingPrice):'No price',b.featured?'Featured':'Standard'].map(x=>`<span class="pill">${x}</span>`).join('');fields.forEach(f=>document.getElementById(f).value=b[f]??'');featured.value=String(Boolean(b.featured));bookingEnabled.value=String(Boolean(b.bookingEnabled));renderBoatCaptainApprovals();loadMedia().catch(e=>renderMediaError(e.message));}
    function formBoat(){const cur=state.boats.find(x=>x.id===state.selectedBoatId)||{};const next={...cur};fields.forEach(f=>next[f]=['lengthFt','capacity','bedrooms','bathrooms','startingPrice'].includes(f)?Number(document.getElementById(f).value||0):document.getElementById(f).value);next.featured=featured.value==='true';next.bookingEnabled=bookingEnabled.value==='true';next.lifecycleStatus=next.status==='active'?'marketable':'draft';return next;}
    async function saveCurrentBoat(){const next=formBoat();const isNew=!state.boats.find(b=>b.id===next.id);const url=isNew?`${api()}/api/v1/boats`:`${api()}/api/v1/boats/${encodeURIComponent(next.id)}`;const r=await fetch(url,{method:isNew?'POST':'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(next)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Save failed');await loadBoats();selectBoat(next.id||d.id);}
    saveBoat.onclick=()=>saveCurrentBoat().catch(e=>alert(e.message));
    deleteBoat.onclick=async()=>{if(!state.selectedBoatId||!confirm('Delete this boat from D1?'))return;const r=await fetch(`${api()}/api/v1/boats/${encodeURIComponent(state.selectedBoatId)}`,{method:'DELETE',headers:adminHeaders()});const d=await r.json();if(!r.ok){alert(d.error||'Delete failed');return;}await loadBoats();showBoatList();};
    backToBoats.onclick=()=>{renderBoats();showBoatList();};
    addBoat.onclick=()=>{const id=`boat_${Date.now()}`;state.boats.push({id,slug:`new-boat-${Date.now()}`,name:'New Cove Boat',status:'draft',lifecycleStatus:'draft',bookingEnabled:false,featured:false,sortOrder:state.boats.length,homePort:'Lake of the Ozarks, MO',lengthFt:0,capacity:0,bedrooms:0,bathrooms:0,make:'',model:'',type:'Type TBD',shortDescription:'',startingPrice:0,priceUnit:'4 hour'});renderBoats();selectBoat(id);};
    async function loadCaptains(){captainLoadStatus.textContent='Loading captains from Cove API...';try{const r=await fetch(`${api()}/api/v1/captains`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load captains');state.captains=d;renderCaptains();if(state.selectedBoatId)renderBoatCaptainApprovals();if(state.selectedCaptainId)renderCaptainBoatApprovals();}catch(e){captainLoadStatus.textContent=e.message;captainList.innerHTML='<div class="item">Could not load captains from API.</div>';}}
    function renderCaptains(){captainList.innerHTML=state.captains.map(c=>`<article class="item click" data-id="${esc(c.id)}"><div class="item-top"><div><h3>${esc(c.name)}</h3><p>${esc(c.credential||'Credential TBD')} | ${esc(c.homePort||'Home port TBD')}</p></div><span class="badge ${c.status==='active'?'good':'bad'}">${esc(c.status)}</span></div><div class="pill-row"><span class="pill">${Number(c.approvedBoatCount||0)} approved boats</span><span class="pill">${esc(c.email||'No email')}</span><span class="pill">${esc(c.phone||'No phone')}</span></div></article>`).join('')||'<div class="item">No captains yet.</div>';captainList.querySelectorAll('.item.click').forEach(i=>i.onclick=()=>selectCaptain(i.dataset.id));captainLoadStatus.textContent=`${state.captains.length} captain records loaded from D1`;renderBookingFilters();}
    function selectCaptain(id){state.selectedCaptainId=id;const c=state.captains.find(x=>x.id===id);if(!c)return;captainName.value=c.name||'';captainStatus.value=c.status||'draft';captainCredential.value=c.credential||'';captainEmail.value=c.email||'';captainPhone.value=c.phone||'';captainHomePort.value=c.homePort||'';captainBio.value=c.bio||'';renderCaptainBoatApprovals();}
    function blankCaptain(){state.selectedCaptainId=null;captainName.value='';captainStatus.value='draft';captainCredential.value='';captainEmail.value='';captainPhone.value='';captainHomePort.value='Lake of the Ozarks, MO';captainBio.value='';renderCaptainBoatApprovals();}
    function formCaptain(){return {id:state.selectedCaptainId,name:captainName.value,status:captainStatus.value,credential:captainCredential.value,email:captainEmail.value,phone:captainPhone.value,homePort:captainHomePort.value,bio:captainBio.value};}
    async function saveCurrentCaptain(){const next=formCaptain();const isNew=!next.id;const url=isNew?`${api()}/api/v1/captains`:`${api()}/api/v1/captains/${encodeURIComponent(next.id)}`;const r=await fetch(url,{method:isNew?'POST':'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(next)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Save captain failed');await loadCaptains();selectCaptain(next.id||d.id);}
    function renderBoatCaptainApprovals(){const boat=state.boats.find(b=>b.id===state.selectedBoatId);if(!boat){boatCaptainApprovals.innerHTML='';return;}const approved=new Set(boat.approvedCaptainIds||[]);boatCaptainApprovals.innerHTML=state.captains.length?state.captains.map(c=>`<label class="item"><span><input type="checkbox" data-boat-captain-id="${esc(c.id)}" ${approved.has(c.id)?'checked':''}> ${esc(c.name)}</span><span class="muted">${esc(c.credential||'Credential TBD')} | ${esc(c.status)}</span></label>`).join(''):'<div class="empty-media">Add captains before assigning them to this boat.</div>';boatCaptainApprovals.querySelectorAll('[data-boat-captain-id]').forEach(input=>input.onchange=saveBoatCaptainApprovals);}
    async function saveBoatCaptainApprovals(){const boat=state.boats.find(b=>b.id===state.selectedBoatId);if(!boat)return;const captainIds=[...boatCaptainApprovals.querySelectorAll('[data-boat-captain-id]:checked')].map(input=>input.dataset.boatCaptainId);boatCaptainStatus.textContent='Saving captain approvals...';const r=await fetch(`${api()}/api/v1/boats/${encodeURIComponent(boat.id)}/captains`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({captainIds})});const d=await r.json();if(!r.ok){boatCaptainStatus.textContent=d.error||'Could not save captain approvals';return;}boat.approvedCaptainIds=captainIds;boatCaptainStatus.textContent=`${captainIds.length} approved captain(s) saved.`;}
    function renderCaptainBoatApprovals(){const captain=state.captains.find(c=>c.id===state.selectedCaptainId);if(!captain){captainBoatApprovals.innerHTML='<div class="empty-media">Select or save a captain before assigning boats.</div>';captainBoatStatus.textContent='Choose which boats this captain is approved for.';return;}captainBoatApprovals.innerHTML=state.boats.length?state.boats.map(b=>`<label class="item"><span><input type="checkbox" data-captain-boat-id="${esc(b.id)}" ${(b.approvedCaptainIds||[]).includes(captain.id)?'checked':''}> ${esc(b.name)}</span><span class="muted">${esc(b.status||'draft')} | ${esc(b.homePort||'Home port TBD')}</span></label>`).join(''):'<div class="empty-media">Add boats before assigning them to this captain.</div>';captainBoatApprovals.querySelectorAll('[data-captain-boat-id]').forEach(input=>input.onchange=()=>saveCaptainBoatApproval(input));captainBoatStatus.textContent=`${Number(captain.approvedBoatCount||0)} approved boat(s).`;}
    async function saveCaptainBoatApproval(input){const captain=state.captains.find(c=>c.id===state.selectedCaptainId);const boat=state.boats.find(b=>b.id===input.dataset.captainBoatId);if(!captain||!boat)return;const current=new Set(boat.approvedCaptainIds||[]);if(input.checked)current.add(captain.id);else current.delete(captain.id);captainBoatStatus.textContent='Saving boat approval...';const captainIds=[...current];const r=await fetch(`${api()}/api/v1/boats/${encodeURIComponent(boat.id)}/captains`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({captainIds})});const d=await r.json();if(!r.ok){captainBoatStatus.textContent=d.error||'Could not save boat approval';input.checked=!input.checked;return;}boat.approvedCaptainIds=captainIds;await loadBoats();await loadCaptains();selectCaptain(captain.id);}
    async function loadBookings({silent=false}={}){if(!silent)bookingLoadStatus.textContent='Loading bookings from Cove API...';try{const r=await fetch(`${api()}/api/v1/bookings?ts=${Date.now()}`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load bookings');state.bookings=d;renderBookings();updateBookingBadges();bookingRefreshStatus.textContent=`Auto-refreshing every 10 seconds. Last updated ${timeText()}.`;}catch(e){bookingRefreshStatus.textContent=`Auto-refresh paused by an error at ${timeText()}: ${e.message}`;if(!silent){bookingLoadStatus.textContent=e.message;bookingList.innerHTML='<div class="item">Could not load bookings from API.</div>';}}}
    async function loadAvailability(){try{const r=await fetch(`${api()}/api/v1/availability?ts=${Date.now()}`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load availability');state.availability=d;renderBookings();}catch(e){availabilityStatusText.textContent=e.message;}}
    function snapHalfHour(input){if(!input?.value)return;const [h,m]=input.value.split(':').map(Number);if(Number.isNaN(h)||Number.isNaN(m))return;let total=h*60+m;total=Math.round(total/30)*30;if(total>=1440)total=1410;input.value=`${String(Math.floor(total/60)).padStart(2,'0')}:${String(total%60).padStart(2,'0')}`;}
    function bindHalfHourTimes(root=document){root.querySelectorAll('input[type="time"]').forEach(input=>{input.step=1800;input.setAttribute('list','halfHourTimes');input.onblur=()=>snapHalfHour(input);input.onchange=()=>snapHalfHour(input);});}
    function populateHalfHourTimes(){const list=document.getElementById('halfHourTimes');if(list)list.innerHTML=Array.from({length:48},(_,i)=>{const total=i*30;return `<option value="${String(Math.floor(total/60)).padStart(2,'0')}:${String(total%60).padStart(2,'0')}"></option>`}).join('');}
    function dateTimeValue(date,time,end=false){if(!date)return '';return `${date}T${time || (end ? '23:30' : '00:00')}`;}
    async function saveAvailabilityBlock(){[availabilityStartTime,availabilityEndTime].forEach(snapHalfHour);const [entityType,entityId]=availabilityResource.value.split(':');const endDate=availabilityEndDate.value&&availabilityEndDate.value>=availabilityStartDate.value?availabilityEndDate.value:availabilityStartDate.value;const payload={entityType,entityId,status:availabilityStatus.value,startAt:dateTimeValue(availabilityStartDate.value,availabilityStartTime.value),endAt:dateTimeValue(endDate,availabilityEndTime.value,true),notes:availabilityNotes.value};if(!payload.entityId||!payload.startAt||!payload.endAt){availabilityStatusText.textContent='Choose a resource and date range.';return;}if(payload.endAt<=payload.startAt){availabilityStatusText.textContent='End must be after start.';return;}availabilityStatusText.textContent='Saving availability block...';const r=await fetch(`${api()}/api/v1/availability`,{method:'POST',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(payload)});const d=await r.json();if(!r.ok){availabilityStatusText.textContent=d.error||'Could not save availability';return;}availabilityEndDate.value=endDate;availabilityNotes.value='';availabilityStatusText.textContent='Availability block saved.';await loadAvailability();}
    async function deleteAvailabilityBlock(id){if(!confirm('Delete this availability block?'))return;const r=await fetch(`${api()}/api/v1/availability/${encodeURIComponent(id)}`,{method:'DELETE',headers:adminHeaders()});const d=await r.json();if(!r.ok){alert(d.error||'Could not delete availability');return;}await loadAvailability();}
    const bookingStatuses=['requested','reviewing','confirmed','completed','declined','cancelled'];
    function renderBookingFilters(){if(!bookingFilterStatus)return;const current={...state.bookingFilters};bookingFilterStatus.innerHTML='<option value="">All statuses</option>'+bookingStatuses.map(s=>`<option value="${s}">${s}</option>`).join('');bookingFilterBoat.innerHTML='<option value="">All boats</option>'+state.boats.map(b=>`<option value="${esc(b.id)}">${esc(b.name)}</option>`).join('');bookingFilterCaptain.innerHTML='<option value="">All captains</option>'+state.captains.map(c=>`<option value="${esc(c.id)}">${esc(c.name)}</option>`).join('');availabilityResource.innerHTML=state.boats.map(b=>`<option value="boat:${esc(b.id)}">Boat: ${esc(b.name)}</option>`).join('')+state.captains.map(c=>`<option value="captain:${esc(c.id)}">Captain: ${esc(c.name)}</option>`).join('');bookingFilterStatus.value=current.status;bookingFilterBoat.value=current.boatId;bookingFilterCaptain.value=current.captainId;bookingFilterFrom.value=current.from;bookingFilterTo.value=current.to;bookingFilterSearch.value=current.search;}
    function readBookingFilters(){state.bookingFilters={status:bookingFilterStatus.value,boatId:bookingFilterBoat.value,captainId:bookingFilterCaptain.value,from:bookingFilterFrom.value,to:bookingFilterTo.value,search:bookingFilterSearch.value.trim().toLowerCase()};}
    function bookingMatchesFilters(b){const f=state.bookingFilters;if(f.status&&b.status!==f.status)return false;if(f.boatId&&b.boatId!==f.boatId)return false;if(f.captainId&&b.captainId!==f.captainId)return false;if(f.from&&(!b.charterDate||b.charterDate<f.from))return false;if(f.to&&(!b.charterDate||b.charterDate>f.to))return false;if(f.search){const text=[b.customerName,b.email,b.phone,b.boatName,b.captainName,b.customerNotes,b.officeNotes,b.status].join(' ').toLowerCase();if(!text.includes(f.search))return false;}return true;}
    function availabilityMatchesFilters(a){const f=state.bookingFilters;if(f.boatId&&!(a.entityType==='boat'&&a.entityId===f.boatId))return false;if(f.captainId&&!(a.entityType==='captain'&&a.entityId===f.captainId))return false;if(f.from&&a.endAt.slice(0,10)<f.from)return false;if(f.to&&a.startAt.slice(0,10)>f.to)return false;if(f.search){const text=[a.status,a.notes,availabilityLabel(a)].join(' ').toLowerCase();if(!text.includes(f.search))return false;}return true;}
    function availabilityLabel(a){return a.entityType==='boat'?(state.boats.find(b=>b.id===a.entityId)?.name||a.entityId):(state.captains.find(c=>c.id===a.entityId)?.name||a.entityId);}
    function filteredBookings(){return [...state.bookings].filter(bookingMatchesFilters);}
    function bookingStart(b){return b.charterDate?`${b.charterDate}T${b.startTime||'00:00'}`:'';}
    function bookingEnd(b){if(!b.charterDate)return '';const start=new Date(bookingStart(b));start.setMinutes(start.getMinutes()+Number(b.durationHours||4)*60);return dateKey(start)+'T'+String(start.getHours()).padStart(2,'0')+':'+String(start.getMinutes()).padStart(2,'0');}
    function conflictsForBooking(b){const start=bookingStart(b);const end=bookingEnd(b);if(!start||!end)return [];return state.availability.filter(a=>(a.entityType==='boat'&&a.entityId===b.boatId||a.entityType==='captain'&&a.entityId===b.captainId)&&a.startAt<end&&a.endAt>start);}
    function possibleConflictNotes(b){return [b.customerNotes,b.officeNotes].filter(Boolean).filter(text=>/availability warning|may not be available|conflict/i.test(text));}
    function dateKey(date){return [date.getFullYear(),String(date.getMonth()+1).padStart(2,'0'),String(date.getDate()).padStart(2,'0')].join('-');}
    function renderCalendar(bookings=filteredBookings()){const month=state.calendarMonth;calendarTitle.textContent=month.toLocaleDateString([], {month:'long',year:'numeric'});const dated=bookings.filter(b=>b.charterDate);const blocks=state.availability.filter(availabilityMatchesFilters);calendarSummary.textContent=`${dated.length} dated booking(s) and ${blocks.length} availability block(s) match the current filters.`;const byDate=dated.reduce((map,b)=>{(map[b.charterDate] ||= []).push({kind:'booking',item:b});return map;},{});blocks.forEach(a=>{const first=a.startAt.slice(0,10);(byDate[first] ||= []).push({kind:'availability',item:a});});const start=new Date(month.getFullYear(),month.getMonth(),1);start.setDate(start.getDate()-start.getDay());const end=new Date(start);end.setDate(start.getDate()+41);const names=['Sun','Mon','Tue','Wed','Thu','Fri','Sat'].map(d=>`<div class="calendar-day-name">${d}</div>`).join('');let cells='';for(let d=new Date(start);d<=end;d.setDate(d.getDate()+1)){const key=dateKey(d);const events=(byDate[key]||[]);cells+=`<div class="calendar-day ${d.getMonth()===month.getMonth()?'':'out'}"><div class="calendar-date">${d.getDate()}</div>${events.map(e=>e.kind==='booking'?`<button class="calendar-event ${bookingTone(e.item.status)}" type="button" data-calendar-booking="${esc(e.item.id)}">${esc(e.item.startTime||'Time TBD')} ${esc(e.item.boatName||e.item.boatId)}<span>${esc(e.item.customerName||'Guest')} | ${esc(e.item.status||'requested')}</span></button>`:`<button class="calendar-event bad" type="button" data-calendar-availability="${esc(e.item.id)}">${esc(e.item.status)}: ${esc(availabilityLabel(e.item))}<span>${esc(e.item.startAt.slice(11,16))}-${esc(e.item.endAt.slice(11,16))} ${esc(e.item.notes||'')}</span></button>`).join('')}</div>`;}bookingCalendar.innerHTML=names+cells;bookingCalendar.querySelectorAll('[data-calendar-booking]').forEach(btn=>btn.onclick=()=>focusBookingCard(btn.dataset.calendarBooking));bookingCalendar.querySelectorAll('[data-calendar-availability]').forEach(btn=>btn.onclick=()=>deleteAvailabilityBlock(btn.dataset.calendarAvailability));}
    function focusBookingCard(id){const card=bookingList.querySelector(`[data-booking-card="${CSS.escape(id)}"]`);if(!card)return;card.scrollIntoView({behavior:'smooth',block:'center'});card.style.outline='3px solid rgba(15,111,143,.45)';setTimeout(()=>card.style.outline='',1600);}
    function bookingTone(status){return ['confirmed','completed','approved','booked'].includes(status)?'good':['requested','declined','cancelled'].includes(status)?'bad':'';}
    function bookingStatusOptions(current){return bookingStatuses.includes(current)?bookingStatuses:[current,...bookingStatuses].filter(Boolean);}
    function approvedCaptainsForBooking(b){const boat=state.boats.find(x=>x.id===b.boatId);const approved=new Set(boat?.approvedCaptainIds||[]);const list=approved.size?state.captains.filter(c=>approved.has(c.id)):state.captains;return b.captainId&&!list.some(c=>c.id===b.captainId)?[...list,state.captains.find(c=>c.id===b.captainId)].filter(Boolean):list;}
    function bookingDraft(id){const read=suffix=>bookingList.querySelector(`[data-booking-${suffix}="${CSS.escape(id)}"]`);snapHalfHour(read('time'));return {status:read('status')?.value||'requested',captainId:read('captain')?.value||null,charterDate:read('date')?.value||null,startTime:read('time')?.value||null,durationHours:Number(read('duration')?.value||4),officeNotes:read('notes')?.value||'',agreementStatus:bookingList.querySelector(`[data-agreement-status="${CSS.escape(id)}"]`)?.value||'not started',signingUrl:bookingList.querySelector(`[data-booking-signing="${CSS.escape(id)}"]`)?.value||''};}
    function closeoutDraft(id){const read=suffix=>bookingList.querySelector(`[data-closeout-${suffix}="${CSS.escape(id)}"]`);return {actualHours:Number(read('hours')?.value||0),paymentStatus:read('payment')?.value||'unsettled',notes:read('notes')?.value||''};}
    function stampNote(existing,line){const stamp=`[${new Date().toLocaleString()}] ${line}`;return [existing,stamp].filter(Boolean).join('\n');}
    function captainPacketReady(b){return ['confirmed','completed'].includes(b.status)&&Boolean(b.captainId);}
    function customerReply(b,type='confirm'){const d=bookingDraft(b.id);const boat=b.boatName||b.boatId||'your charter';const date=d.charterDate||b.charterDate||'the requested date';const start=d.startTime||b.startTime||'the requested time';const captain=state.captains.find(c=>c.id===d.captainId)?.name||b.captainName||'your captain';if(type==='decline')return `Hi ${b.customerName||'there'}, thanks for reaching out to Cove Charters. We are sorry, but ${boat} is not available for ${date} at ${start}. We would be happy to help find another option.`;return `Hi ${b.customerName||'there'}, thanks for your Cove Charters request. We can confirm ${boat} for ${date} at ${start} for ${Number(d.durationHours||b.durationHours||4)} hours. ${captain} is currently assigned. Please reply here with any questions or changes.`;}
    function agreementPacket(b){const d=bookingDraft(b.id);const captain=state.captains.find(c=>c.id===d.captainId)?.name||b.captainName||'Captain TBD';return [`Cove Charters agreement packet`,`Booking: ${b.id}`,`Customer: ${b.customerName||'Guest'}`,`Email: ${b.email||'Not provided'}`,`Phone: ${b.phone||'Not provided'}`,`Boat: ${b.boatName||b.boatId}`,`Captain selected by customer: ${captain}`,`Charter date/time: ${d.charterDate||b.charterDate||'Date TBD'} ${d.startTime||b.startTime||''}`,`Duration: ${Number(d.durationHours||b.durationHours||0)} hours`,'',`Bareboat note: customer must independently select and approve their captain from the boat-approved captain list. Cove should not assign the captain on the customer's behalf.`,'',`Checklist:`,`- Confirm customer identity and contact details`,`- Confirm boat, date, start time, and duration`,`- Confirm customer captain selection`,`- Send bareboat charter agreement`,`- Collect signed agreement before trip`,`- Confirm payment/deposit status`,`- Attach agreement copy for back office and captain`].join('\n');}
    function captainPacket(b){const d=bookingDraft(b.id);const captain=state.captains.find(c=>c.id===d.captainId)||{};const conflicts=conflictsForBooking({...b,captainId:d.captainId,charterDate:d.charterDate,startTime:d.startTime,durationHours:d.durationHours});return [`Cove captain trip packet`,`Booking: ${b.id}`,`Captain: ${captain.name||b.captainName||'Captain TBD'}`,`Captain email: ${captain.email||b.captainEmail||'Not provided'}`,`Captain phone: ${captain.phone||b.captainPhone||'Not provided'}`,'',`Boat: ${b.boatName||b.boatId}`,`Date/time: ${d.charterDate||b.charterDate||'Date TBD'} ${d.startTime||b.startTime||''}`,`Duration: ${Number(d.durationHours||b.durationHours||0)} hours`,`Agreement status: ${d.agreementStatus}`,'',`Customer: ${b.customerName||'Guest'}`,`Customer phone: ${b.phone||'Not provided'}`,`Customer email: ${b.email||'Not provided'}`,'',`Customer notes: ${b.customerNotes||'None'}`,`Office notes: ${d.officeNotes||b.officeNotes||'None'}`,`Availability warnings: ${conflicts.length?conflicts.map(availabilityLabel).join('; '):'None'}`].join('\n');}
    function settlementSummary(b){const d=bookingDraft(b.id);const closeout=closeoutDraft(b.id);return [`Cove settlement summary`,`Booking: ${b.id}`,`Status: ${d.status}`,`Customer: ${b.customerName||'Guest'}`,`Boat: ${b.boatName||b.boatId}`,`Captain: ${state.captains.find(c=>c.id===d.captainId)?.name||b.captainName||'Captain TBD'}`,`Scheduled: ${d.charterDate||b.charterDate||'Date TBD'} ${d.startTime||b.startTime||''}`,`Scheduled hours: ${Number(d.durationHours||b.durationHours||0)}`,`Actual hours: ${closeout.actualHours||Number(d.durationHours||b.durationHours||0)}`,`Payment status: ${closeout.paymentStatus}`,`Agreement status: ${d.agreementStatus}`,`Closeout notes: ${closeout.notes||'None'}`,`Office notes: ${d.officeNotes||b.officeNotes||'None'}`].join('\n');}
    function agreementStatusFromNotes(b){const matches=[...String(b.officeNotes||'').matchAll(/Agreement status: ([^\n]+)/g)];return matches.length?matches.at(-1)[1].trim():'not started';}
    function agreementStatus(b){return b.agreementStatus||agreementStatusFromNotes(b);}
    function documentPanel(b){const docs=b.documents||[];const signatures=b.signatures||[];const signingLink=b.signingUrl?`<a class="pill" href="${esc(b.signingUrl)}" target="_blank" rel="noopener">Open customer signing packet</a>`:'<span class="pill">No signing link generated yet</span>';const links=docs.length?docs.map(doc=>`<a class="pill" href="${esc(doc.url)}" target="_blank" rel="noopener">${esc(doc.title||doc.documentType)} (${esc(doc.status||'uploaded')})</a>`).join(''):'<span class="pill">No uploaded documents attached</span>';const sigs=signatures.length?signatures.map(sig=>`<a class="pill" href="#booking-${esc(b.id)}">Signed by ${esc(sig.signerName)} ${esc(sig.signedAt||'')}</a>`).join(''):'<span class="pill">No electronic signature yet</span>';return `<div class="panel" style="box-shadow:none;border-radius:18px"><div class="panel-head"><h2>Documents</h2></div><div class="panel-body"><label class="full">Signing link<input data-booking-signing="${esc(b.id)}" value="${esc(b.signingUrl||'')}" placeholder="Leave blank to generate Cove signing link"></label><div class="pill-row">${signingLink}${links}${sigs}</div><div class="booking-grid"><label class="wide">Signed document URL<input data-doc-url="${esc(b.id)}" placeholder="https://...signed-agreement.pdf"></label><label>Title<input data-doc-title="${esc(b.id)}" value="Signed bareboat charter agreement"></label><label>Status<select data-doc-status="${esc(b.id)}"><option value="signed">signed</option><option value="uploaded">uploaded</option><option value="final">final</option></select></label></div><div class="actions"><button class="btn light" type="button" data-add-document="${esc(b.id)}">Attach Document</button></div></div></div>`;}
    function bookingSummary(b){const d=bookingDraft(b.id);return [`Cove booking request: ${b.id}`,`Customer: ${b.customerName||'Guest'}`,`Phone: ${b.phone||'Not provided'}`,`Email: ${b.email||'Not provided'}`,`Boat: ${b.boatName||b.boatId}`,`Captain: ${state.captains.find(c=>c.id===d.captainId)?.name||b.captainName||'Captain TBD'}`,`Date/time: ${d.charterDate||b.charterDate||'Date TBD'} ${d.startTime||b.startTime||''}`,`Duration: ${Number(d.durationHours||b.durationHours||0)} hours`,`Status: ${d.status||b.status}`,`Customer notes: ${b.customerNotes||'None'}`,`Office notes: ${d.officeNotes||b.officeNotes||'None'}`].join('\n');}
    function renderBookings(){renderBookingFilters();const sorted=filteredBookings().sort((a,b)=>(a.status==='requested'?0:1)-(b.status==='requested'?0:1)||String(b.createdAt||'').localeCompare(String(a.createdAt||'')));renderCalendar(sorted);bookingList.innerHTML=sorted.map(b=>{const captains=approvedCaptainsForBooking(b);const conflicts=conflictsForBooking(b);const warningNotes=possibleConflictNotes(b);const conflictLines=conflicts.length?conflicts.map(a=>`${esc(a.status)}: ${esc(availabilityLabel(a))} ${esc(a.startAt)} to ${esc(a.endAt)}`):warningNotes.map(esc);return `<article class="item booking-card" id="booking-${esc(b.id)}" data-booking-card="${esc(b.id)}"><div class="item-top"><div><h3>${esc(b.customerName||'Guest')}</h3><p>${esc(b.boatName||b.boatId)} | ${esc(b.charterDate||'Date TBD')} ${esc(b.startTime||'')}</p></div><span class="badge ${bookingTone(b.status)}">${esc(b.status)}</span></div><div class="pill-row"><span class="pill">${esc(b.email||'No email')}</span><span class="pill">${esc(b.phone||'No phone')}</span><span class="pill">${esc(b.captainName||'Captain TBD')}</span><span class="pill">${Number(b.durationHours||0)} hours</span></div>${conflictLines.length?`<div class="conflict-warning"><strong>Possible Conflict</strong><p>${conflictLines.join('<br>')}</p></div>`:''}<div class="booking-grid"><label>Status<select data-booking-status="${esc(b.id)}">${bookingStatusOptions(b.status).map(s=>`<option value="${s}" ${b.status===s?'selected':''}>${s}</option>`).join('')}</select></label><label class="wide">Captain<select data-booking-captain="${esc(b.id)}"><option value="">Captain TBD</option>${captains.map(c=>`<option value="${esc(c.id)}" ${b.captainId===c.id?'selected':''}>${esc(c.name)}</option>`).join('')}</select></label><label>Agreement<select data-agreement-status="${esc(b.id)}" ${['confirmed','completed'].includes(b.status)?'':'disabled'}><option value="not started" ${agreementStatus(b)==='not started'?'selected':''}>not started</option><option value="drafted" ${agreementStatus(b)==='drafted'?'selected':''}>drafted</option><option value="sent" ${agreementStatus(b)==='sent'?'selected':''}>sent</option><option value="signed" ${agreementStatus(b)==='signed'?'selected':''}>signed</option></select></label><label>Date<input type="date" data-booking-date="${esc(b.id)}" value="${esc(b.charterDate||'')}"></label><label>Start time<input type="time" step="1800" list="halfHourTimes" data-booking-time="${esc(b.id)}" value="${esc(b.startTime||'')}"></label><label>Hours<input type="number" min="1" step="0.5" data-booking-duration="${esc(b.id)}" value="${Number(b.durationHours||4)}"></label></div><div class="booking-notes"><label>Customer notes<textarea readonly>${esc(b.customerNotes||'No customer notes yet.')}</textarea></label><label>Office notes<textarea data-booking-notes="${esc(b.id)}" placeholder="Availability checks, partner call notes, payment details...">${esc(b.officeNotes||'')}</textarea></label></div>${documentPanel(b)}<div class="booking-grid"><label>Actual hours<input type="number" min="0" step="0.5" data-closeout-hours="${esc(b.id)}" value="${Number(b.durationHours||4)}"></label><label>Payment<select data-closeout-payment="${esc(b.id)}"><option value="unsettled">unsettled</option><option value="deposit paid">deposit paid</option><option value="paid in full">paid in full</option><option value="needs review">needs review</option></select></label><label class="wide">Closeout notes<input data-closeout-notes="${esc(b.id)}" placeholder="Actual hours, fuel, cleaning, damage, tip, payout notes..."></label></div><div class="actions"><button class="btn sand" type="button" data-save-booking="${esc(b.id)}">Save Booking</button><button class="btn light" type="button" data-confirm-booking="${esc(b.id)}">Confirm</button><button class="btn light" type="button" data-followup-booking="${esc(b.id)}">Needs Follow-up</button><button class="btn danger" type="button" data-decline-booking="${esc(b.id)}">Decline</button><button class="btn light" type="button" data-copy-booking="${esc(b.id)}">Copy Summary</button><button class="btn light" type="button" data-copy-confirm="${esc(b.id)}">Copy Confirmation</button><button class="btn sand" type="button" data-send-confirmation="${esc(b.id)}" ${['confirmed','completed'].includes(b.status)?'':'disabled'}>Send Confirmation</button><button class="btn light" type="button" data-copy-decline="${esc(b.id)}">Copy Decline</button><button class="btn light" type="button" data-copy-agreement="${esc(b.id)}" ${['confirmed','completed'].includes(b.status)?'':'disabled'}>Copy Agreement Packet</button><button class="btn sand" type="button" data-send-agreement="${esc(b.id)}" ${['confirmed','completed'].includes(b.status)?'':'disabled'}>Send Agreement Packet</button><button class="btn light" type="button" data-copy-captain="${esc(b.id)}" ${captainPacketReady(b)?'':'disabled'}>Copy Captain Packet</button><button class="btn sand" type="button" data-send-captain="${esc(b.id)}" ${captainPacketReady(b)?'':'disabled'}>Send Captain Packet</button><button class="btn light" type="button" data-copy-settlement="${esc(b.id)}" ${['confirmed','completed'].includes(b.status)?'':'disabled'}>Copy Settlement Summary</button><button class="btn sand" type="button" data-complete-trip="${esc(b.id)}" ${['confirmed','completed'].includes(b.status)?'':'disabled'}>Complete Trip</button></div><p class="muted copy-status" data-booking-copy-status="${esc(b.id)}"></p></article>`}).join('')||'<div class="item">No booking requests match these filters.</div>';bookingLoadStatus.textContent=`${sorted.length} of ${state.bookings.length} booking request(s) shown`;bookingList.querySelectorAll('[data-save-booking]').forEach(btn=>btn.onclick=()=>saveBooking(btn.dataset.saveBooking).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-confirm-booking]').forEach(btn=>btn.onclick=()=>quickBookingAction(btn.dataset.confirmBooking,'confirm').catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-followup-booking]').forEach(btn=>btn.onclick=()=>quickBookingAction(btn.dataset.followupBooking,'followup').catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-decline-booking]').forEach(btn=>btn.onclick=()=>quickBookingAction(btn.dataset.declineBooking,'decline').catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-copy-booking]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copyBooking,'summary'));bookingList.querySelectorAll('[data-copy-confirm]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copyConfirm,'confirm'));bookingList.querySelectorAll('[data-send-confirmation]').forEach(btn=>btn.onclick=()=>sendBookingConfirmation(btn.dataset.sendConfirmation).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-send-agreement]').forEach(btn=>btn.onclick=()=>sendAgreementPacket(btn.dataset.sendAgreement).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-add-document]').forEach(btn=>btn.onclick=()=>addBookingDocument(btn.dataset.addDocument).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-copy-decline]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copyDecline,'decline'));bookingList.querySelectorAll('[data-copy-agreement]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copyAgreement,'agreement'));bookingList.querySelectorAll('[data-copy-captain]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copyCaptain,'captain'));bookingList.querySelectorAll('[data-send-captain]').forEach(btn=>btn.onclick=()=>sendCaptainPacket(btn.dataset.sendCaptain).catch(e=>alert(e.message)));bookingList.querySelectorAll('[data-copy-settlement]').forEach(btn=>btn.onclick=()=>copyBookingText(btn.dataset.copySettlement,'settlement'));bookingList.querySelectorAll('[data-complete-trip]').forEach(btn=>btn.onclick=()=>completeTrip(btn.dataset.completeTrip).catch(e=>alert(e.message)));bindHalfHourTimes(bookingList);updateBookingBadges();}
    function showBookingStatus(id,message,tone='good'){const el=bookingList.querySelector(`[data-booking-copy-status="${CSS.escape(id)}"]`);if(!el)return;el.textContent=message;el.classList.add('show');el.classList.toggle('good',tone==='good');el.classList.toggle('bad',tone==='bad');}
    async function copyBookingText(id,type){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;const text=type==='summary'?bookingSummary(booking):type==='agreement'?agreementPacket(booking):type==='captain'?captainPacket(booking):type==='settlement'?settlementSummary(booking):customerReply(booking,type);await navigator.clipboard.writeText(text);showBookingStatus(id,`Copied ${type==='summary'?'internal summary':type} message.`);}
    async function sendBookingConfirmation(id){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;showBookingStatus(id,'Sending confirmation email...');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/send-confirmation`,{method:'POST',headers:adminHeaders()});const d=await r.json();if(r.status===501){await navigator.clipboard.writeText(customerReply(booking,'confirm'));showBookingStatus(id,'Customer email is not configured. Confirmation copied instead.','bad');return;}if(!r.ok){showBookingStatus(id,d.error||'Could not send confirmation','bad');throw new Error(d.error||'Could not send confirmation');}showBookingStatus(id,'Confirmation email sent.');setTimeout(()=>loadBookings(),1200);}
    async function sendAgreementPacket(id){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;const draft=bookingDraft(id);const missing=[];if(!booking.boatId)missing.push('boat');if(!draft.captainId)missing.push('captain');if(!draft.charterDate)missing.push('date');if(!draft.startTime)missing.push('start time');if(!draft.durationHours)missing.push('hours');if(missing.length){showBookingStatus(id,`Add ${missing.join(', ')} before sending the agreement packet.`,'bad');return;}showBookingStatus(id,'Saving booking details before sending agreement...');await saveBooking(id,{silent:true});showBookingStatus(id,'Sending guided agreement packet...');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/send-agreement-packet`,{method:'POST',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({signingUrl:draft.signingUrl})});const d=await r.json();if(r.status===501){await navigator.clipboard.writeText(agreementPacket(booking));showBookingStatus(id,'Customer email is not configured. Agreement packet copied instead.','bad');return;}if(!r.ok){showBookingStatus(id,d.error||'Could not send agreement packet','bad');throw new Error(d.error||'Could not send agreement packet');}showBookingStatus(id,'Agreement packet sent.');setTimeout(()=>loadBookings(),1200);}
    async function sendCaptainPacket(id){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;showBookingStatus(id,'Sending captain packet...');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/send-captain-packet`,{method:'POST',headers:adminHeaders()});const d=await r.json();if(r.status===501){await navigator.clipboard.writeText(captainPacket(booking));showBookingStatus(id,'Captain email is not configured. Packet copied instead.','bad');return;}if(!r.ok){showBookingStatus(id,d.error||'Could not send captain packet','bad');throw new Error(d.error||'Could not send captain packet');}showBookingStatus(id,'Captain packet sent.');setTimeout(()=>loadBookings(),1200);}
    async function addBookingDocument(id){const url=bookingList.querySelector(`[data-doc-url="${CSS.escape(id)}"]`)?.value.trim();const title=bookingList.querySelector(`[data-doc-title="${CSS.escape(id)}"]`)?.value.trim()||'Signed charter document';const status=bookingList.querySelector(`[data-doc-status="${CSS.escape(id)}"]`)?.value||'uploaded';if(!url){showBookingStatus(id,'Paste a signed document URL first.','bad');return;}showBookingStatus(id,'Attaching signed document...');const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}/documents`,{method:'POST',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({url,title,status,documentType:'bareboat_agreement',audience:'captain,office'})});const d=await r.json();if(!r.ok){showBookingStatus(id,d.error||'Could not attach document','bad');throw new Error(d.error||'Could not attach document');}showBookingStatus(id,'Signed document attached.');setTimeout(()=>loadBookings(),900);}
    async function completeTrip(id){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;const draft=bookingDraft(id);const closeout=closeoutDraft(id);draft.status='completed';draft.officeNotes=stampNote(draft.officeNotes,`Trip completed. Actual hours: ${closeout.actualHours||draft.durationHours}. Payment: ${closeout.paymentStatus}. Closeout notes: ${closeout.notes||'None'}`);const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(draft)});const d=await r.json();if(!r.ok){showBookingStatus(id,d.error||'Could not complete trip','bad');throw new Error(d.error||'Could not complete trip');}const statusEl=bookingList.querySelector(`[data-booking-status="${CSS.escape(id)}"]`);if(statusEl)statusEl.value='completed';await navigator.clipboard.writeText(settlementSummary(booking));showBookingStatus(id,'Trip completed. Settlement summary copied.');setTimeout(()=>loadBookings(),1200);}
    async function saveBooking(id,options={}){const payload=bookingDraft(id);if(['confirmed','completed'].includes(payload.status))payload.officeNotes=stampNote(payload.officeNotes,`Agreement status: ${payload.agreementStatus}`);const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(payload)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not save booking');if(!options.silent)await loadBookings();return d;}
    async function quickBookingAction(id,action){const booking=state.bookings.find(b=>b.id===id);if(!booking)return;const status=action==='confirm'?'confirmed':action==='decline'?'declined':'reviewing';const message=action==='confirm'?'Confirmed booking and copied customer confirmation.':action==='decline'?'Declined request and copied customer decline message.':'Marked needs follow-up.';const draft=bookingDraft(id);draft.status=status;draft.officeNotes=stampNote(draft.officeNotes,message);const r=await fetch(`${api()}/api/v1/bookings/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify(draft)});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not update booking');if(action==='confirm')await navigator.clipboard.writeText(customerReply(booking,'confirm'));if(action==='decline')await navigator.clipboard.writeText(customerReply(booking,'decline'));await loadBookings();}
    function refreshBookingsNow(){if(document.activeElement?.matches?.('[data-booking-status],[data-booking-captain],[data-booking-date],[data-booking-time],[data-booking-duration],[data-booking-notes],[data-booking-signing],[data-doc-url],[data-doc-title]'))return;loadBookings({silent:true});}
    function startBookingAutoRefresh(){setInterval(()=>{if(!document.hidden)refreshBookingsNow();},10000);window.addEventListener('focus',refreshBookingsNow);document.addEventListener('visibilitychange',()=>{if(!document.hidden)refreshBookingsNow();});}
    async function loadMedia(){if(!state.selectedBoatId)return;const r=await fetch(`${api()}/api/v1/media?entityType=boat&entityId=${encodeURIComponent(state.selectedBoatId)}`,{cache:'no-store'});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not load media');state.media=d;renderMedia();}
    function renderMedia(){const photos=sortMedia(state.media.filter(m=>m.mediaType==='photos'));const videos=sortMedia(state.media.filter(m=>m.mediaType==='videos'));const cover=photos.find(m=>m.isCover);coverMedia.innerHTML=cover?mediaCard(cover,false):'<div class="empty-media">No cover selected.</div>';photoGallery.innerHTML=photos.length?photos.map(m=>mediaCard(m,true)).join(''):'<div class="empty-media">No gallery photos yet.</div>';videoGallery.innerHTML=videos.length?videos.map(m=>mediaCard(m,true)).join(''):'<div class="empty-media">No videos yet.</div>';bindMediaDrag(photoGallery,'photos');bindMediaDrag(videoGallery,'videos');document.querySelectorAll('[data-cover-id]').forEach(btn=>btn.onclick=()=>setCover(btn.dataset.coverId).catch(e=>alert(e.message)));document.querySelectorAll('[data-delete-media]').forEach(btn=>btn.onclick=()=>deleteMedia(btn.dataset.deleteMedia).catch(e=>alert(e.message)));document.querySelectorAll('[data-caption-id]').forEach(input=>{input.onkeydown=e=>{if(e.key==='Enter'){e.preventDefault();input.blur();}};input.onchange=()=>saveCaption(input.dataset.captionId,input.value).catch(e=>alert(e.message));});}
    function sortMedia(items){return [...items].sort((a,b)=>Number(a.sortOrder||0)-Number(b.sortOrder||0)||String(a.createdAt||'').localeCompare(String(b.createdAt||'')));}
    function bindMediaDrag(container,mediaType){container.querySelectorAll('.media-card').forEach(card=>{card.ondragstart=e=>{card.classList.add('dragging');e.dataTransfer.effectAllowed='move';e.dataTransfer.setData('text/plain',card.dataset.id);};card.ondragend=()=>card.classList.remove('dragging');card.ondragover=e=>{e.preventDefault();e.dataTransfer.dropEffect='move';};card.ondrop=e=>{e.preventDefault();reorderMedia(e.dataTransfer.getData('text/plain'),card.dataset.id,mediaType).catch(err=>alert(err.message));};});}
    function mediaCard(m,draggable=true){const caption=m.title||'';const media=m.mediaType==='videos'?`<video src="${esc(m.url)}" controls></video>`:`<img src="${esc(m.url)}" alt="${esc(m.alt||m.title||'Boat media')}">`;return `<article class="media-card ${m.isCover?'cover':''}" draggable="${draggable?'true':'false'}" data-id="${esc(m.id)}" data-type="${esc(m.mediaType)}">${media}<input data-caption-id="${esc(m.id)}" value="${esc(caption)}" placeholder="spacious interior"><span class="muted">${m.isCover?'Cover photo':`Sort ${m.sortOrder}`}</span><div class="actions">${m.mediaType==='photos'?`<button class="btn light" type="button" data-cover-id="${esc(m.id)}">Set Cover</button>`:''}<button class="btn danger" type="button" data-delete-media="${esc(m.id)}">Delete</button></div></article>`}
    function renderMediaError(message){coverMedia.innerHTML=`<div class="empty-media">${message}</div>`;photoGallery.innerHTML='<div class="empty-media">Media unavailable.</div>';videoGallery.innerHTML='<div class="empty-media">Media unavailable.</div>';}
    async function setCover(id){const r=await fetch(`${api()}/api/v1/media/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({isCover:true})});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not set cover');await loadMedia();}
    async function deleteMedia(id){const item=state.media.find(m=>m.id===id);const label=item?.title||item?.url||'this media item';if(!confirm(`Delete ${label}? This removes it from the boat gallery.`))return;const r=await fetch(`${api()}/api/v1/media/${encodeURIComponent(id)}`,{method:'DELETE',headers:adminHeaders()});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not delete media');await loadMedia();}
    async function saveCaption(id,title){const clean=title.trim();const item=state.media.find(m=>m.id===id);if(!item||clean===String(item.title||''))return;const r=await fetch(`${api()}/api/v1/media/${encodeURIComponent(id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({title:clean,alt:clean})});const d=await r.json();if(!r.ok)throw new Error(d.error||'Could not save caption');state.media=state.media.map(m=>m.id===id?{...m,title:clean,alt:clean}:m);}
    async function reorderMedia(sourceId,targetId,mediaType){if(!sourceId||!targetId||sourceId===targetId)return;const items=sortMedia(state.media.filter(m=>m.mediaType===mediaType));const from=items.findIndex(m=>m.id===sourceId);const to=items.findIndex(m=>m.id===targetId);if(from<0||to<0)return;const [moved]=items.splice(from,1);items.splice(to,0,moved);state.media=state.media.map(item=>item.mediaType===mediaType?{...item,sortOrder:items.findIndex(m=>m.id===item.id)}:item);renderMedia();await Promise.all(items.map((m,i)=>fetch(`${api()}/api/v1/media/${encodeURIComponent(m.id)}`,{method:'PUT',headers:adminHeaders({'Content-Type':'application/json'}),body:JSON.stringify({sortOrder:i})}).then(async r=>{if(!r.ok)throw new Error((await r.json()).error||'Could not sort media')})));await loadMedia();}
    async function uploadFiles(files,mediaType,statusEl){if(!state.selectedBoatId){alert('Save/select a boat first.');return;}if(!files.length){alert('Choose at least one file first.');return;}const b=state.boats.find(x=>x.id===state.selectedBoatId);statusEl.textContent=`Uploading ${files.length} file(s)...`;let count=0;for(const file of files){const form=new FormData();form.append('file',file);form.append('entityType','boat');form.append('entityId',b.id);form.append('entitySlug',b.slug||b.id);form.append('mediaType',mediaType);form.append('title',file.name);const r=await fetch(`${api()}/api/v1/media`,{method:'POST',headers:adminHeaders(),body:form});const d=await r.json();if(!r.ok)throw new Error(d.error||'Upload failed');count++;}await loadMedia();statusEl.textContent=`Uploaded ${count} file(s).`;}
    uploadBoatPhotos.onclick=()=>uploadFiles(boatPhotoFiles.files,'photos',boatPhotoUploadStatus).catch(e=>boatPhotoUploadStatus.textContent=e.message);
    uploadBoatVideos.onclick=()=>uploadFiles(boatVideoFiles.files,'videos',boatVideoUploadStatus).catch(e=>boatVideoUploadStatus.textContent=e.message);
    function renderJson(){jsonBox.textContent=JSON.stringify(state.boats,null,2);}
    saveCaptain.onclick=()=>saveCurrentCaptain().catch(e=>alert(e.message));
    newCaptain.onclick=blankCaptain;
    deleteCaptain.onclick=async()=>{if(!state.selectedCaptainId||!confirm('Delete this captain from D1?'))return;const r=await fetch(`${api()}/api/v1/captains/${encodeURIComponent(state.selectedCaptainId)}`,{method:'DELETE',headers:adminHeaders()});const d=await r.json();if(!r.ok){alert(d.error||'Delete captain failed');return;}blankCaptain();await loadCaptains();await loadBoats();};
    reloadCaptains.onclick=loadCaptains;
    reloadBookings.onclick=()=>{loadBookings();loadAvailability();};
    populateHalfHourTimes();bindHalfHourTimes();saveAvailability.onclick=()=>saveAvailabilityBlock().catch(e=>availabilityStatusText.textContent=e.message);
    [bookingFilterStatus,bookingFilterBoat,bookingFilterCaptain,bookingFilterFrom,bookingFilterTo].forEach(el=>el.onchange=()=>{readBookingFilters();renderBookings();});
    bookingFilterSearch.oninput=()=>{readBookingFilters();renderBookings();};
    clearBookingFilters.onclick=()=>{state.bookingFilters={status:'',boatId:'',captainId:'',from:'',to:'',search:''};renderBookings();};
    calendarPrev.onclick=()=>{state.calendarMonth=new Date(state.calendarMonth.getFullYear(),state.calendarMonth.getMonth()-1,1);renderBookings();};
    calendarNext.onclick=()=>{state.calendarMonth=new Date(state.calendarMonth.getFullYear(),state.calendarMonth.getMonth()+1,1);renderBookings();};
    calendarToday.onclick=()=>{const now=new Date();state.calendarMonth=new Date(now.getFullYear(),now.getMonth(),1);renderBookings();};
    resetBoats.onclick=loadBoats;
    loadHealth();loadBoats();loadCaptains();loadBookings();loadAvailability();blankCaptain();startBookingAutoRefresh();
